sql:
SELECT actors.actor_name, movies.movie_title
FROM actors
INNER JOIN movies ON actors.actor_id = movies.movie_id;

SELECT actor_name, date_of_birth, nationality, agency
FROM actors
WHERE actor_id = 1;

SELECT COUNT(DISTINCT actor_id) 
FROM awards 
WHERE award_name = 'Best Actor' AND award_year = 2022;

